func SanitizeProtoInput(input string) string {
	input = strings.ReplaceAll(input, "\r\n", "\n")
	input = strings.TrimSpace(input)
	return input
}

func ValidateProtoDefinition(protoContent string) error {
	if len(protoContent) == 0 {
		return fmt.Errorf("proto definition is empty")
	}
	
	if len(protoContent) > 1024*1024 {
		return fmt.Errorf("proto definition exceeds maximum size of 1MB")
	}
	
	if !strings.Contains(protoContent, "syntax") {
		return fmt.Errorf("proto definition must contain syntax declaration")
	}
	
	return nil
}